fun solve(nums: Array<Long>, queries: Array<Array<Long>>): Long {
    val MOD = 1000000007
    val n = nums.size
    val xorResult = LongArray(n)

    for (i in 0 until n) {
        xorResult[i] = nums[i]
    }

    for (query in queries) {
        val li = query[0].toLong()
        val ri = query[1].toLong()
        val ki = query[2].toLong()
        val vi = query[3].toLong()

        var idx = li
        while (idx <= ri) {
            xorResult[idx.toInt()] = (xorResult[idx.toInt()] * vi) % MOD
            idx += ki
        }
    }

    var result = 0L
    for (num in xorResult) {
        result = result xor num
    }

    return result
}
